          "store": "orders",
          "access": "read_write",
          "purpose": "Check order status and update to cancelled"
        },
        {
          "store": "payments",
          "access": "read_write",
          "purpose": "Process refund for cancelled order"
        },
        {
          "store": "inventory",
          "access": "read_write",
          "purpose": "Restore inventory for cancelled order"
        }
      ]
    },
    {
      "name": "TrackOrder",
      "call_inputs": [
        {
          "name": "order_data",
          "type": "Any",
          "description": "Contains order_id to track",
          "source": "ParseCommand output via parent"
        }
      ],
      "call_outputs": [
        {
          "name": "result",
          "type": "Any",
          "description": "JSON with success, order_id, status, message, tracking_info",
          "consumer": "parent"
        }
      ],
      "internal_leaf_accesses": [
        {
          "store": "orders",
          "access": "read",
          "purpose": "Retrieve order status and tracking details"
        }
      ]
    }
  ]
}
